from flask import Flask, request, jsonify
import os
import redis

app = Flask(__name__)

redis_client = redis.Redis(
    host=os.getenv("REDIS_HOST", "localhost"),
    port=int(os.getenv("REDIS_PORT", "6379")),
    db=int(os.getenv("REDIS_DB", "0")),
    password=os.getenv("REDIS_PASSWORD"),
    decode_responses=True,
)

ALLOWED_COMMANDS = {
    "PING": {"arity": 0},
    "GET": {"arity": 1},
    "MGET": {"arity_min": 1},
    "SET": {"arity_min": 2},
    "DEL": {"arity_min": 1},
    "EXISTS": {"arity_min": 1},
    "EXPIRE": {"arity": 2},
    "TTL": {"arity": 1},
    "PTTL": {"arity": 1},
    "INCR": {"arity": 1},
    "INCRBY": {"arity": 2},
    "DECR": {"arity": 1},
    "DECRBY": {"arity": 2},
    "HGET": {"arity": 2},
    "HSET": {"arity_min": 3},
    "HGETALL": {"arity": 1},
    "HDEL": {"arity_min": 2},
    "LPUSH": {"arity_min": 2},
    "RPUSH": {"arity_min": 2},
    "LPOP": {"arity": 1},
    "RPOP": {"arity": 1},
    "LRANGE": {"arity": 3},
    "SADD": {"arity_min": 2},
    "SREM": {"arity_min": 2},
    "SMEMBERS": {"arity": 1},
    "ZADD": {"arity_min": 3},
    "ZRANGE": {"arity_min": 3},
    "ZREM": {"arity_min": 2},
}

def parse_command(command_str):
    if not command_str or not command_str.strip():
        raise ValueError("Missing command")
    parts = command_str.strip().split()
    if not parts:
        raise ValueError("Invalid command")
    cmd = parts[0].upper()
    args = parts[1:]
    if cmd not in ALLOWED_COMMANDS:
        raise ValueError(f"Command not allowed: {cmd}")
    spec = ALLOWED_COMMANDS[cmd]
    if "arity" in spec and len(args) != spec["arity"]:
        raise ValueError(f"{cmd} requires exactly {spec['arity']} argument(s)")
    if "arity_min" in spec and len(args) < spec["arity_min"]:
        raise ValueError(f"{cmd} requires at least {spec['arity_min']} argument(s)")
    return cmd, args

@app.route("/admin/redis", methods=["GET", "POST"])
def admin_redis():
    command_str = request.args.get("command") or request.form.get("command") or (request.json or {}).get("command") if request.is_json else None
    try:
        cmd, args = parse_command(command_str)
        result = redis_client.execute_command(cmd, *args)
        return jsonify({
            "ok": True,
            "command": cmd,
            "args": args,
            "result": result,
        })
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    except redis.RedisError as e:
        return jsonify({"ok": False, "error": str(e)}), 502
    except Exception:
        return jsonify({"ok": False, "error": "Internal server error"}), 500

@app.route("/health", methods=["GET"])
def health():
    try:
        pong = redis_client.ping()
        return jsonify({"ok": True, "redis": pong})
    except Exception:
        return jsonify({"ok": False, "redis": False}), 503

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))